var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"방금…… 보셨습니까?","JPN":"今の……見ましたか？","ENG":"Did you... just see that?","TWN":"剛剛……你有看到嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그, 그래. 정말로 지휘관님이 그림자를 쓰러트렸어.","JPN":"あ、ああ。本当に指揮官がシャドウを倒したぞ。","ENG":"Y-yeah... He really defeated that Shadow.","TWN":"有…指揮官真的擊倒暗影。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"뭐야? 아냐… 이건 말도 안 돼.","JPN":"何？　嘘……あり得ないわ。","ENG":"What? No... There's no way...!","TWN":"搞什麼？不會的…這怎麼可能！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"어떻게 한 거지? 넌 도대체 뭐야?","JPN":"どうやったの？　あんたはいったい何なの？","ENG":"How is that possible?! Who are you?!","TWN":"怎樣會這樣？你到底何方神聖？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"남부 국경수비대 소속 지휘대장, 제라드 큐리안이다.","JPN":"南部国境守備隊所属の指揮隊長、ジェラード・キュリアンだ。","ENG":"I am Gerard Curian. Commanding Officer of the Southern Border Guards.","TWN":"他就是隸屬於南方國境護衛隊的指揮隊長 傑瑞德· 庫里安。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"……큐리안?","JPN":"……キュリアン？","ENG":"Curian...?!","TWN":"……庫里安？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"헛소리! 녀석은 내가 죽였어!","JPN":"ふざけないで！　あいつはあたしが殺したの！","ENG":"Nonsense! I killed him years ago!","TWN":"胡說！那傢伙是我殺死的！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"네 녀석도 이미 죽어 그림자가 됐지만, 아직 자신이 살아 있다고 믿고 있지.","JPN":"貴様もすでに死んでシャドウになっているが、まだ自分が生きてると信じている。","ENG":"You also died and became a Shadow, but you still believe you're alive, no?","TWN":"你也是死後變成暗影，但相信自己還活著吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"악기에 기생하는 망령인 주제에, 참 모순된 이야기지 않나?","JPN":"楽器に寄生する亡霊のくせに、矛盾していないか？","ENG":"You're a ghost living inside an instrument. Don't you think that's hypocritical of you?","TWN":"明明寄生在樂器上的亡靈，這不是矛盾嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그래. 예전의 난 이미 죽었어.","JPN":"そうだね。昔のあたしはすでに死んでる。","ENG":"Yeah, I died a long time ago.","TWN":"沒錯，以前的我已死，"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그리고 연주자로서 새 삶을 얻었고, 이번엔 다른 녀석의 몸으로 되살아났지.","JPN":"そして演奏者として新しい人生を手に入れて、今度は他のやつの体で蘇ったよ。","ENG":"And I was reborn a musician. Now, I'm alive once again in this woman's body.","TWN":"然而，我又重生為一位演奏家，這次是用另一個人軀體復活。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"하지만 그게 너희 빌어먹을 인간들도 가능하다는 뜻은 아니야!","JPN":"でもあんたらのようなクソ人間にもそれができるという意味ではないわ！","ENG":"But that doesn't mean it's possible for pathetic humans like you, too!","TWN":"但這不代表你們這些該死的傢伙也能做到！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"넌 그런 걸로 만족하는 건가?","JPN":"貴様はそれで満足してるのか？","ENG":"Are you satisfied with that?","TWN":"這樣你便心滿意足嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"안식에 들지 못한 채, 집착에 사로잡힌 망령이 된다는 게 말이다.","JPN":"安らかに眠れず、執着にとらわれた亡霊になることにだ。","ENG":"You're a wandering ghost. Caught in her own obsession, never able to rest in peace.","TWN":"意思就是，你無法進入安息，只能成為有執念的亡靈。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"네 말대로 우리의 삶은 죽음으로 끝난다.","JPN":"貴様の言うとおり、我々の人生は死で終わる。","ENG":"Like you said, our lives end after death.","TWN":"正如你所說，我們的生命以死亡告終。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 새로운 이들이 우리의 이름을 기억하고 그 의지를 잇는 한, 죽음은 결코 두려워할 것이 못 된다.","JPN":"だが、新しい者たちが我々の名を記憶し、その意志を受け継ぐ限り、死なんぞ決して恐れるほどのものではない。","ENG":"However, as long as others remember our names and carry us with them in their determination, death is nothing to be afraid of.","TWN":"但是，只要新一代的人記得我們的名字，並且繼承我們的意志，死亡就不可怕。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런 우리의 숭고한 역사를……. 고작 죽음을 거스르는 것 따위에 빗대지 마라. 그림자.","JPN":"そういう我々の尊い歴史を……死に逆らうものなんぞに例えるな。シャドウ。","ENG":"Don't you dare compare your immortality to our noble history, Shadow.","TWN":"別拿死亡……來和人類偉大的歷史相比，暗影。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"좋아. 알겠어.","JPN":"いいわ。わかった。","ENG":"All right. Fine.","TWN":"很好，沒問題。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그럼 어디 한 번 시험해 볼까?","JPN":"それじゃあ、試してみる？","ENG":"Let's find out then, shall we?","TWN":"那就來試試吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그 모가지가 찢어진 뒤에도 계속 그런 허울 좋은 소리를 지껄일 수 있는지.","JPN":"その首が千切れた後もそんな上っ面のいいことばっかり言えるかどうか。","ENG":"Let's see if you keep talking nonsense after I rip your head off your shoulders!","TWN":"我倒要看看你的腦袋離開身體後，還能繼續說大話嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};